<section class="page-heading"><div><p class="eyebrow">Gestão</p><h1>Administração</h1></div><a href="/auditoria">Consultar auditoria</a></section><section class="panel"><h2>Usuários de acesso</h2><form method="get" class="filters"><label>Pesquisa<input name="q" value="<?=e(isset($_GET['q'])?$_GET['q']:'')?>"></label><label>Perfil<select name="perfil"><option value="">Todos</option><?php foreach(array('administrador','homologador','unidade_apuradora','usuario_companhia')as$p):?><option <?=isset($_GET['perfil'])&&$_GET['perfil']===$p?'selected':''?>><?=e($p)?></option><?php endforeach;?></select></label><button>Filtrar</button></form><div class="table-wrap"><table><thead><tr><th>Matrícula</th><th>Nome</th><th>Perfil</th><th>Unidade</th><th>Ativo</th></tr></thead><tbody><?php foreach($users['items']as$u):?><tr><td><?=e($u['matricula'])?></td><td><?=e($u['nome'])?></td><td><?=e($u['perfil'])?></td><td><?=e($u['sg_unidade'].' - '.$u['no_unidade'])?></td><td><?=!empty($u['ativo'])?'Sim':'Não'?></td></tr><?php endforeach;?></tbody></table></div><h3>Novo usuário</h3><form method="post" action="/administracao/usuarios" class="editor-form"><input type="hidden" name="_csrf_token" value="<?=e(Auth::csrfToken())?>"><label>Matrícula<input name="matricula" required></label><label>Nome<input name="nome" required></label><label>Perfil<select name="perfil"><?php foreach(array('administrador','homologador','unidade_apuradora','usuario_companhia')as$p):?><option><?=e($p)?></option><?php endforeach;?></select></label><label>Sigla da unidade<input name="sg_unidade"></label><label>Nome da unidade<input name="no_unidade"></label><input type="hidden" name="ativo" value="1"><button>Adicionar</button></form></section><section class="panel"><h2>Configurações</h2><?php foreach($configs as$c):?><form method="post" action="/administracao/configuracoes/<?=e(rawurlencode($c['chave']))?>"><input type="hidden" name="_csrf_token" value="<?=e(Auth::csrfToken())?>"><label><?=e($c['chave'])?><textarea name="valor" <?=$c['sensivel']?'disabled':''?>><?=e(is_array($c['valor'])?json_encode($c['valor'],JSON_UNESCAPED_UNICODE|JSON_PRETTY_PRINT):$c['valor'])?></textarea></label><?php if(!$c['sensivel']):?><button>Salvar</button><?php endif;?></form><?php endforeach;?></section><section class="panel"><h2>Usuários de validação</h2><p><?=count($validation)?> registro(s) disponíveis para consulta.</p></section>
